2959                        "versioning:");
2960   LLVM_DEBUG(dbgs() << "  Ptr: " << *Ptr << " Stride: " << *StrideExpr << "\n");
2961 
2962   if (!SpeculateUnitStride) {
2963     LLVM_DEBUG(dbgs() << "  Chose not to due to -laa-speculate-unit-stride\n");
2964     return;
2965   }
2966 
