2991   if (BETypeSizeBits >= StrideTypeSizeBits)
2992     CastedStride = SE->getNoopOrSignExtend(StrideExpr, BETakenCount->getType());
2993   else
2994     CastedBECount = SE->getZeroExtendExpr(BETakenCount, StrideExpr->getType());
